/// Log line with metadata
pub struct LogLine {
    /// Timestamp
    pub timestamp: DateTime<Utc>,
    /// Log level
    pub level: LogLevel,
    /// Source module
    pub module: String,
    /// Message content
    pub message: String,
    /// Rendered height (cached)
    cached_height: OnceCell<u16>,
}

impl RenderItem for LogLine {
    fn render(&self, area: Rect, buf: &mut Buffer, budget: &RenderBudget) {
        let style = match self.level {
            LogLevel::Error => Style::default().fg(Color::Red),
            LogLevel::Warn => Style::default().fg(Color::Yellow),
            LogLevel::Info => Style::default().fg(Color::White),
            LogLevel::Debug => Style::default().fg(Color::Gray),
            LogLevel::Trace => Style::default().fg(Color::DarkGray),
        };

        // Format: [HH:MM:SS] [LEVEL] module: message
        let prefix = format\!(
            "[{}] [{:5}] {}: ",
            self.timestamp.format("%H:%M:%S"),
            self.level,
            self.module
        );

        if budget.degradation().apply_styling() {
            buf.set_string(area.x, area.y, &prefix, style);
            buf.set_string(
                area.x + prefix.len() as u16,
                area.y,
                &self.message,
                Style::default(),
            );
        } else {
            let full = format\!("{}{}", prefix, self.message);
            buf.set_string(area.x, area.y, &full, Style::default());
        }
    }

    fn height(&self) -> u16 {
        *self.cached_height.get_or_init(|| 1)  // Could calculate wrapped height
    }
}

/// Log viewer with virtualization
pub struct LogViewer {
    /// Virtualized log storage
    logs: VirtualizedList<LogLine>,

    /// Filter pattern
    filter: Option<Regex>,

    /// Whether to follow new output
    follow: bool,

    /// Search state
    search: Option<SearchState>,

    /// Syntax highlighter (optional)
    highlighter: Option<SyntaxHighlighter>,
}

impl LogViewer {
    pub fn new(capacity: usize) -> Self {
        Self {
            logs: VirtualizedList::new(Virtualized::new(Vec::with_capacity(capacity))),
            filter: None,
            follow: true,
            search: None,
            highlighter: None,
        }
    }

    /// Append log line
    pub fn append(&mut self, line: LogLine) {
        self.logs.data.push(line);
        if self.follow {
            self.logs.data.scroll_to_bottom();
        }
    }

    /// Append batch of log lines
    pub fn append_batch(&mut self, lines: impl Iterator<Item = LogLine>) {
        for line in lines {
            self.logs.data.push(line);
        }
        if self.follow {
            self.logs.data.scroll_to_bottom();
        }
    }

    /// Set filter pattern
    pub fn set_filter(&mut self, pattern: Option<&str>) -> Result<(), regex::Error> {
        self.filter = pattern.map(Regex::new).transpose()?;
        Ok(())
    }

    /// Toggle follow mode
    pub fn toggle_follow(&mut self) {
        self.follow = \!self.follow;
        if self.follow {
            self.logs.data.scroll_to_bottom();
        }
    }

    /// Search for text
    pub fn search(&mut self, query: &str) -> Vec<usize> {
        let mut matches = Vec::new();
        for (idx, line) in self.logs.data.iter().enumerate() {
            if line.message.contains(query) {
                matches.push(idx);
            }
        }
        self.search = Some(SearchState {
            query: query.to_string(),
            matches: matches.clone(),
            current: 0,
        });
        matches
    }

    /// Jump to next search match
    pub fn next_match(&mut self) {
        if let Some(search) = &mut self.search {
            if \!search.matches.is_empty() {
                search.current = (search.current + 1) % search.matches.len();
                self.logs.data.scroll_to(search.matches[search.current]);
            }
        }
    }
}

impl Widget for LogViewer {
    fn render(&self, area: Rect, buf: &mut Buffer, budget: &RenderBudget) {
        // Draw border
        let block = Block::default()
            .borders(Borders::ALL)
            .title("Logs")
            .title_alignment(Alignment::Left);

        let inner = block.inner(area);
        block.render(area, buf);

        // Render virtualized list
        self.logs.render(inner, buf, budget);

        // Status line at bottom
        self.render_status(area, buf);
    }
}
